"import sys\nimport os\nimport json\nimport urllib.request\n\ndef main():\n    if len(sys.argv) < 3:\n        print(\"ERROR: Missing text or output path\")\n        sys.exit(1)\n        \n    text = sys.argv[1]\n    output_path = sys.argv[2]\n    \n    api_key = sys.argv[3] if len(sys.argv) > 3 else \"\"\n    base_url = sys.argv[4] if len(sys.argv) > 4 else \"https://api.openai.com/v1\"\n    model = sys.argv[5] if len(sys.argv) > 5 else \"tts-1\"\n    voice = sys.argv[6] if len(sys.argv) > 6 else \"alloy\"\n    \n    if not api_key:\n        print(\"ERROR: Missing API Key for custom TTS\")\n        sys.exit(1)\n        \n    url = f\"{base_url.rstrip('/')}/audio/speech\"\n    \n    payload = {\n        \"model\": model,\n        \"input\": text,\n        \"voice\": voice\n    }\n    \n    headers = {\n        \"Authorization\": f\"Bearer {api_key}\",\n        \"Content-Type\": \"application/json\"\n    }\n    \n    try:\n        req = urllib.request.Request(\n            url, \n            data=json.dumps(payload).encode(\"utf-8\"), \n            headers=headers, \n            method=\"POST\"\n        )\n        \n        with urllib.request.urlopen(req, timeout=15) as response:\n            audio_bytes = response.read()\n            with open(output_path, \"wb\") as f:\n                f.write(audio_bytes)\n            print(\"SUCCESS\")\n    except Exception as e:\n        print(f\"ERROR: {str(e)}\")\n        sys.exit(1)\n\nif __name__ == \"__main__\":\n    main()\n"